// Input: array of working schedule objects
const schedules = $input.all();

function isWithinWorkingHours(schedule) {
  const timezone = schedule.json.timezone;

  // Get current time in the specified timezone
  const now = new Date();

  // Get the current day of week
  const dayFormatter = new Intl.DateTimeFormat('en-US', {
    timeZone: timezone,
    weekday: 'long'
  });
  const currentDay = dayFormatter.format(now);

  // Get the current hour (0-23)
  const timeFormatter = new Intl.DateTimeFormat('en-US', {
    timeZone: timezone,
    hour: 'numeric',
    hour12: false
  });
  const timeString = timeFormatter.format(now);
  const currentHour = parseInt(timeString, 10);

  // Check if current day is in working days
  if (!schedule.json.workingDays.includes(currentDay)) {
    return false;
  }

  // Check if current hour is within working hours
  // If endHour is 19, it means up to and including 18:xx (before 19:00)
  const startHour = schedule.json.startHour;
  const endHour = schedule.json.endHour;

  return currentHour >= startHour && currentHour < endHour;
}

// Process each schedule and return array of results
return schedules.map(schedule => ({
  json: {
    isWithinWorkingHours: isWithinWorkingHours(schedule),
    currentTimezone: schedule.json.timezone,
    schedule: schedule.json
  }
}));

