const results = [];

// Loop through every item received from the previous node
for (const item of $input.all()) {
  const raw = item.json.query.e164 || "";
  const email = item.json.query.email;

  // 1. Clean the number (remove non-digits)
  let digits = raw.replace(/\D/g, '');

  // 2. Standardize to the UK "0" format
  let nationalBase = digits;
  if (digits.startsWith('44')) {
    nationalBase = '0' + digits.slice(2);
  } else if (!digits.startsWith('0') && digits.length === 10) {
    nationalBase = '0' + digits;
  }

  // 3. Define the different UK formats
  const variations = [
    nationalBase,                                        // 01394432013
    "+44" + nationalBase.slice(1),                      // +441394432013
    nationalBase.slice(0, 5) + " " + nationalBase.slice(5), // 01394 432013
    "+44 " + nationalBase.slice(1, 5) + " " + nationalBase.slice(5) // +44 1394 432013
  ];

  // 4. Create the specific structure n8n requires: { json: { ... } }
  variations.forEach(v => {
    results.push({
      json: {
        query: {
          e164: v,
          email: email
        }
      }
    });
  });
}

return results;

