// Parse the JSON string to get properties array
const propertiesData = JSON.parse(rawData);

// Extract essential info for each property
const outputData = propertiesData.map(prop => ({
  // Property Identity
  id: prop.id,
  reference: prop.fullReference,

  // Address
  address: prop.displayAddress,
  city: prop.city,
  county: prop.county,
  postal_code: prop.postalCode,
  country: prop.country,

  // Property Details
  property_type: prop.propertyType,
  transaction_type: prop.transactionType,
  bedrooms: prop.bedrooms,
  bathrooms: prop.bathrooms,
  receptions: prop.receptions,

  // Price & Tenure
  price: prop.price,
  currency: prop.priceCurrency,
  tenure: prop.tenure,
  rent_frequency: prop.rentFrequency,

  // Status
  status: prop.status,
  sale_progression: prop.saleProgression,

  // Location
  latitude: prop.latitude,
  longitude: prop.longitude,

  // Dates
  date_created: prop.dtsCreated,
  date_updated: prop.dtsUpdated,
  date_of_instruction: prop.dateOfInstruction,

  // Agent Info
  branch_id: prop.branch?.id,
  branch_name: prop.branch?.name,
  agent_id: prop.user?.id,
  agent_name: `${prop.user?.firstName || ''} ${prop.user?.lastName || ''}`.trim(),
  agent_email: prop.user?.email
}));

// Return the extracted data
return outputData.map(property => ({ json: property }));

// n8n Code Node - Property Matcher
// Filters properties based on search criteria

// Get search query from Edit Fields node
const searchQuery = $('Edit Fields3').first().json.query;

// Get all properties from previous Code node
const allProperties = $('Code in JavaScript16').all().map(item => item.json);

// Helper function to check if property matches criteria
function matchesQuery(property, query) {
  let score = 0;
  let maxScore = 0;

  // City match (highest priority)
  if (query.city) {
    maxScore += 10;
    if (property.city && property.city.toLowerCase().includes(query.city.toLowerCase())) {
      score += 10;
    }
  }

  // Postal code match
  if (query.postalCode) {
    maxScore += 5;
    if (property.postal_code && property.postal_code.toLowerCase().includes(query.postalCode.toLowerCase())) {
      score += 5;
    }
  }

  // Transaction type match (sale/rent)
  if (query.transactionType) {
    maxScore += 8;
    if (property.transaction_type === query.transactionType) {
      score += 8;
    }
  }

  // Property type match
  if (query.propertyType) {
    maxScore += 6;
    const queryType = query.propertyType.toLowerCase();
    const propType = (property.property_type || '').toLowerCase();

    // Exact match
    if (propType === queryType) {
      score += 6;
    }
    // Partial match (e.g., "flat" matches "apartment")
    else if (
      (queryType === 'flat' && propType === 'apartment') ||
      (queryType === 'apartment' && propType === 'flat') ||
      propType.includes(queryType) ||
      queryType.includes(propType)
    ) {
      score += 4;
    }
  }

  // Minimum bedrooms
  if (query.minBeds) {
    maxScore += 5;
    const minBeds = parseInt(query.minBeds);
    if (property.bedrooms >= minBeds) {
      score += 5;
    } else if (property.bedrooms >= minBeds - 1) {
      // Close match (1 bedroom less)
      score += 3;
    }
  }

  // Maximum price
  if (query.maxPrice) {
    maxScore += 5;
    const maxPrice = parseFloat(query.maxPrice);
    const propPrice = parseFloat(property.price);
    if (propPrice <= maxPrice) {
      score += 5;
    } else if (propPrice <= maxPrice * 1.2) {
      // Within 20% of max price
      score += 3;
    }
  }

  return { score, maxScore, percentage: maxScore > 0 ? (score / maxScore) * 100 : 0 };
}

// Score all properties
const scoredProperties = allProperties.map(property => {
  const match = matchesQuery(property, searchQuery);
  return {
    ...property,
    match_score: match.score,
    match_percentage: Math.round(match.percentage),
    is_match: match.percentage >= 50 // Consider it a match if 50% or more criteria met
  };
});

// Sort by match score (highest first)
