  currency: property.currency,

  // Branch and agent (visible)
  branch_name: property.branch_name,
  agent_name: property.agent_name,

  // Match info
  match_percentage: property.match_percentage,
  is_match: property.is_match,

  // Branch ID (secretly included in output but not prominently displayed)
  _branch_id: property.branch_id,

  // All other fields
  ...property
}));

// Return all properties sorted by match percentage (highest first)
return output.map(property => ({ json: property }));

