// Function to convert string booleans to actual booleans
function convertStringBooleans(obj) {
  if (Array.isArray(obj)) {
    return obj.map(item => convertStringBooleans(item));
  } else if (obj !== null && typeof obj === 'object') {
    const newObj = {};
    for (const key in obj) {
      newObj[key] = convertStringBooleans(obj[key]);
    }
    return newObj;
  } else if (obj === 'true') {
    return true;
  } else if (obj === 'false') {
    return false;
  }
  return obj;
}

// Process all items
return items.map(item => ({
  json: convertStringBooleans(item.json)
}));

