  if (typeof obj !== 'object' || obj === null) {
    return obj;
  }

  if (Array.isArray(obj)) {
    return obj.map(item => decodeObjectValues(item));
  }

  const decodedObj = {};
  for (const [key, value] of Object.entries(obj)) {
    if (typeof value === 'string') {
      // Decode URL-encoded string
      let decodedValue = decodeURIComponent(value);

      // Convert boolean strings to actual booleans
      if (decodedValue === 'true') {
        decodedObj[key] = true;
      } else if (decodedValue === 'false') {
        decodedObj[key] = false;
      } else {
        decodedObj[key] = decodedValue;
      }
    } else if (typeof value === 'object' && value !== null) {
      // Recursively decode nested objects
      decodedObj[key] = decodeObjectValues(value);
    } else {
      decodedObj[key] = value;
    }
  }

  return decodedObj;
}

// Process each item and decode URL-encoded values
const processedItems = items.map(item => {
  return {
    json: decodeObjectValues(item.json)
  };
});

return processedItems;
